package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testGetIgnoreEmptyLines() {
        // Given
        boolean expected = true;
        csvFormat = csvFormat.withIgnoreEmptyLines(expected);

        // When
        boolean result = csvFormat.getIgnoreEmptyLines();

        // Then
        assertEquals(expected, result);
    }

    @Test
    public void testGetIgnoreEmptyLinesDefault() {
        // Given
        boolean expected = true;

        // When
        boolean result = csvFormat.getIgnoreEmptyLines();

        // Then
        assertEquals(expected, result);
    }

    @Test
    public void testGetIgnoreEmptyLinesAfterChange() {
        // Given
        boolean expected = false;
        csvFormat = csvFormat.withIgnoreEmptyLines(false);

        // When
        boolean result = csvFormat.getIgnoreEmptyLines();

        // Then
        assertEquals(expected, result);
    }
}
